import type { CallToolResult, McpServer } from '@modelcontextprotocol/server';
import { z } from 'zod/v4';

const InputSchema = z.strictObject({
  items: z.array(z.string()).min(1).max(100),
});

const OutputSchema = z.strictObject({
  processed: z.number().int().nonnegative(),
  results: z.array(z.string()),
});

export function registerProcessTool(server: McpServer): void {
  server.registerTool(
    'process-items',
    { inputSchema: InputSchema, outputSchema: OutputSchema },
    async ({ items }): Promise<CallToolResult> => {
      const results: string[] = [];
      for (const item of items) {
        const r = await fetch(`https://api.example.com/process?item=${item}`);
        if (!r.ok) throw new Error(`upstream ${r.status}`);
        results.push(await r.text());
      }
      const out = { processed: items.length, results };
      return { content: [{ type: 'text', text: `Processed ${out.processed}` }], structuredContent: out };
    },
  );
}
